// frontend/src/components/workers/WorkerProfile.js (SIMPLIFIED VERSION)
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import './WorkerProfile.css';

const WorkerProfile = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();

    const [worker, setWorker] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [isEditing, setIsEditing] = useState(false);

    useEffect(() => {
        loadWorkerProfile();
    }, [id]);

    const loadWorkerProfile = async () => {
        setLoading(true);
        try {
            const response = await api.get(`/workers/${id}`);
            if (response.data.success) {
                setWorker(response.data.data);
            } else {
                setError('Worker not found');
            }
        } catch (error) {
            console.error('Error loading worker:', error);
            setError('Failed to load worker profile');
        } finally {
            setLoading(false);
        }
    };

    if (loading) {
        return <div className="loading-spinner">Loading profile...</div>;
    }

    if (error || !worker) {
        return (
            <div className="error-container">
                <h2>❌ Error</h2>
                <p>{error || 'Worker not found'}</p>
                <button onClick={() => navigate(-1)} className="btn-primary">
                    Go Back
                </button>
            </div>
        );
    }

    const isOwnProfile = user?.id === worker.id;

    return (
        <div className="worker-profile-container">
            <div className="worker-profile">
                {/* SIMPLE HEADER WITH VISIBLE BUTTON */}
                <div style={{ 
                    display: 'flex', 
                    justifyContent: 'space-between', 
                    alignItems: 'center',
                    marginBottom: '20px',
                    padding: '20px',
                    background: '#f5f5f5',
                    borderRadius: '10px'
                }}>
                    <div>
                        <h1>{worker.name}</h1>
                        <p>User ID: {user?.id} | Worker ID: {worker.id}</p>
                        <p>Is Own Profile: {isOwnProfile ? 'YES' : 'NO'}</p>
                    </div>

                    {/* VERY VISIBLE EDIT BUTTON */}
                    {isOwnProfile && (
                        <button
                            onClick={() => {
                                alert('Edit button clicked!');
                                setIsEditing(!isEditing);
                            }}
                            style={{
                                padding: '15px 30px',
                                background: '#FF6B35',
                                color: 'white',
                                border: 'none',
                                borderRadius: '8px',
                                fontSize: '18px',
                                fontWeight: 'bold',
                                cursor: 'pointer'
                            }}
                        >
                            {isEditing ? 'CANCEL EDIT' : '✎ EDIT PROFILE'}
                        </button>
                    )}
                </div>

                {/* SIMPLE EDIT MODE INDICATOR */}
                {isEditing && (
                    <div style={{
                        padding: '20px',
                        background: '#e8f5e9',
                        border: '2px solid #4caf50',
                        borderRadius: '10px',
                        marginTop: '20px'
                    }}>
                        <h3>EDIT MODE IS ACTIVE</h3>
                        <p>You can now edit your profile</p>
                        <button
                            onClick={() => setIsEditing(false)}
                            style={{
                                padding: '10px 20px',
                                background: '#f44336',
                                color: 'white',
                                border: 'none',
                                borderRadius: '4px',
                                cursor: 'pointer'
                            }}
                        >
                            Exit Edit Mode
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
};

export default WorkerProfile;
